import{_ as s,o as i,c as n,a2 as e}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"个人自测中的认知走查","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/validation/10-self-test-cognitive-walkthrough.md","filePath":"03-interaction-design/notes/validation/10-self-test-cognitive-walkthrough.md","lastUpdated":1784248569000}'),l={name:"03-interaction-design/notes/validation/10-self-test-cognitive-walkthrough.md"};function t(r,a,p,h,d,o){return i(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="个人自测中的认知走查" tabindex="-1">个人自测中的认知走查 <a class="header-anchor" href="#个人自测中的认知走查" aria-label="Permalink to &quot;个人自测中的认知走查&quot;">​</a></h1><p>个人自测认知走查是在没有独立参与者时，由设计者或学习者严格按照目标用户知识假设和任务脚本，逐步检查正确子目标、入口发现、动作理解与进展反馈。它能快速暴露明显的可学习性缺口，但检查者知道产品结构，必须控制熟悉度偏差并降低结论强度。</p><h2 id="与普通自测的区别" tabindex="-1">与普通自测的区别 <a class="header-anchor" href="#与普通自测的区别" aria-label="Permalink to &quot;与普通自测的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>普通自测</th><th>个人认知走查</th></tr></thead><tbody><tr><td>按自己熟悉路径完成</td><td>先写目标用户知道与不知道什么</td></tr><tr><td>看到问题立即修改</td><td>先记录每一步事实、四问和失败过程</td></tr><tr><td>关注是否能完成</td><td>关注首次用户为什么会或不会选择正确动作</td></tr><tr><td>依赖自己的记忆</td><td>使用冻结任务、证据和判断脚本</td></tr><tr><td>结论容易写成偏好</td><td>结论限定为潜在问题与待验证假设</td></tr></tbody></table><p>个人走查不能代表真实用户。它适合初筛、学习和迭代早期；高风险、复杂或广泛用户产品仍需其他证据。</p><h2 id="四问框架" tabindex="-1">四问框架 <a class="header-anchor" href="#四问框架" aria-label="Permalink to &quot;四问框架&quot;">​</a></h2><p>对每个必要动作回答：</p><ol><li>用户会形成正确子目标吗？</li><li>用户会发现正确操作吗？</li><li>用户会把操作与预期结果联系起来吗？</li><li>操作后，反馈会让用户知道取得正确进展吗？</li></ol><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K[&quot;用户已有知识&quot;] --&gt; G[&quot;形成当前子目标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; N[&quot;发现可用动作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    N --&gt; A[&quot;理解并执行动作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; F[&quot;从反馈判断进展&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>回答“是”也要写支持证据。没有证据时写未知，不用自己会操作作为理由。</p><h2 id="控制熟悉度偏差" tabindex="-1">控制熟悉度偏差 <a class="header-anchor" href="#控制熟悉度偏差" aria-label="Permalink to &quot;控制熟悉度偏差&quot;">​</a></h2><h3 id="延迟执行" tabindex="-1">延迟执行 <a class="header-anchor" href="#延迟执行" aria-label="Permalink to &quot;延迟执行&quot;">​</a></h3><p>完成设计后间隔一段时间再走查，避免短期记忆直接提供路径。延迟不能消除长期产品知识，只是降低对刚完成细节的依赖。</p><h3 id="隐藏设计稿说明" tabindex="-1">隐藏设计稿说明 <a class="header-anchor" href="#隐藏设计稿说明" aria-label="Permalink to &quot;隐藏设计稿说明&quot;">​</a></h3><p>只保留用户能看到的界面，不查看交互标注、组件名、代码和流程图。走查过程中不打开后台或日志找路径。</p><h3 id="使用角色卡" tabindex="-1">使用角色卡 <a class="header-anchor" href="#使用角色卡" aria-label="Permalink to &quot;使用角色卡&quot;">​</a></h3><p>明确：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>知道：浏览器基本导航、任务对象名称、已持有输入</span></span>
<span class="line"><span>不知道：内部团队名、隐藏快捷键、状态码、设置位置</span></span>
<span class="line"><span>权限：具体角色</span></span>
<span class="line"><span>环境：设备、输入、语言、网络</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="从多个入口开始" tabindex="-1">从多个入口开始 <a class="header-anchor" href="#从多个入口开始" aria-label="Permalink to &quot;从多个入口开始&quot;">​</a></h3><p>使用通知、深链、搜索、失败恢复和首页导航，避免因为设计者记得唯一入口而漏掉真实路径。</p><h3 id="反向寻找失败证据" tabindex="-1">反向寻找失败证据 <a class="header-anchor" href="#反向寻找失败证据" aria-label="Permalink to &quot;反向寻找失败证据&quot;">​</a></h3><p>每个“是”都问：什么条件会变成“否”？例如长文案、无权限、触屏、缩放、加载中或对象已变化。</p><h3 id="交换检查" tabindex="-1">交换检查 <a class="header-anchor" href="#交换检查" aria-label="Permalink to &quot;交换检查&quot;">​</a></h3><p>若有同伴，可交换不同模块进行走查，但不要求用户访谈。检查者仍可能具备技术知识，报告要说明。</p><h2 id="准备脚本" tabindex="-1">准备脚本 <a class="header-anchor" href="#准备脚本" aria-label="Permalink to &quot;准备脚本&quot;">​</a></h2><h3 id="冻结任务" tabindex="-1">冻结任务 <a class="header-anchor" href="#冻结任务" aria-label="Permalink to &quot;冻结任务&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>场景：收到项目即将逾期通知</span></span>
<span class="line"><span>目标：把任务 T-204 的截止日期改为 2026-07-22</span></span>
<span class="line"><span>角色：项目编辑者</span></span>
<span class="line"><span>设备：移动浏览器</span></span>
<span class="line"><span>完成：详情和刷新后均显示新日期</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>不能写“打开更多菜单并选择修改日期”。</p><h3 id="冻结正确动作序列" tabindex="-1">冻结正确动作序列 <a class="header-anchor" href="#冻结正确动作序列" aria-label="Permalink to &quot;冻结正确动作序列&quot;">​</a></h3><p>记录当前实现的一个或多个有效路径，但走查时折叠答案。每个动作包括前置状态和可见结果。</p><h3 id="准备状态" tabindex="-1">准备状态 <a class="header-anchor" href="#准备状态" aria-label="Permalink to &quot;准备状态&quot;">​</a></h3><p>主路径之外准备无权限、无效输入、慢请求、冲突和成功。首次用户也会遇到失败，不能只检查理想状态。</p><h2 id="逐步记录模板" tabindex="-1">逐步记录模板 <a class="header-anchor" href="#逐步记录模板" aria-label="Permalink to &quot;逐步记录模板&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### 步骤 N</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 当前状态与可见信息：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 正确动作：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q1 子目标：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q2 发现：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q3 关联：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Q4 反馈：是/否/未知；证据</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 可能错误动作与结果：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 熟悉度污染：我是否因内部知识知道答案？</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 修复候选与验证：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="完整案例-自测-从通知恢复失败的上传" tabindex="-1">完整案例：自测“从通知恢复失败的上传” <a class="header-anchor" href="#完整案例-自测-从通知恢复失败的上传" aria-label="Permalink to &quot;完整案例：自测“从通知恢复失败的上传”&quot;">​</a></h2><h3 id="角色卡与任务" tabindex="-1">角色卡与任务 <a class="header-anchor" href="#角色卡与任务" aria-label="Permalink to &quot;角色卡与任务&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>知道：曾选择一个 18 MB PDF；收到“上传未完成”通知</span></span>
<span class="line"><span>不知道：上传任务中心位置、会话 ID、是否能续传</span></span>
<span class="line"><span>权限：项目编辑者</span></span>
<span class="line"><span>环境：Android 移动 Web，网络已恢复</span></span>
<span class="line"><span>目标：继续上传 roadmap-v3.pdf，并确认服务端处理完成</span></span>
<span class="line"><span>完成：项目中出现 V3，状态为可查看；没有重复版本</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>正确路径：通知深链 → 登录 → 上传任务详情 → 重试/续传 → 服务端处理 → 结果详情。</p><h3 id="步骤-1-打开通知" tabindex="-1">步骤 1：打开通知 <a class="header-anchor" href="#步骤-1-打开通知" aria-label="Permalink to &quot;步骤 1：打开通知&quot;">​</a></h3><ul><li>Q1：会形成“恢复上传”子目标，因为通知说明“上传未完成”。</li><li>Q2：通知主体可点击，但操作按钮只写“查看”，未说明查看什么，发现尚可。</li><li>Q3：通知含文件名和项目名，可以把入口与任务关联。</li><li>Q4：打开后先进入登录，页面没有说明登录后返回上传，进展反馈未知。</li><li>熟悉度污染：设计者知道重定向会保留，目标用户无法从页面确认。</li></ul><p>问题 ST-CW-01：认证中断缺少任务保留说明。候选是登录页显示“登录后继续上传 roadmap-v3.pdf”，并保留安全对象上下文。</p><h3 id="步骤-2-登录后进入任务详情" tabindex="-1">步骤 2：登录后进入任务详情 <a class="header-anchor" href="#步骤-2-登录后进入任务详情" aria-label="Permalink to &quot;步骤 2：登录后进入任务详情&quot;">​</a></h3><ul><li>Q1：用户希望继续，子目标明确。</li><li>Q2：页面同时有“重新选择文件”和“继续上传”；正确动作可见。</li><li>Q3：“继续上传”与目标直接关联，但没有说明从 45% 继续还是重新开始。</li><li>Q4：选择后进度从 45% 开始，支持正确反馈。</li></ul><p>问题 ST-CW-02：操作后能理解，但执行前无法预测流量和时间。修复为“从 45% 继续上传”。</p><h3 id="步骤-3-传输完成" tabindex="-1">步骤 3：传输完成 <a class="header-anchor" href="#步骤-3-传输完成" aria-label="Permalink to &quot;步骤 3：传输完成&quot;">​</a></h3><ul><li>当前界面显示“上传完成”和 100%，后台仍在解析。</li><li>Q1：用户可能认为目标已经完成，不再形成“等待处理”的子目标。</li><li>Q2：有一个弱视觉“查看处理状态”链接。</li><li>Q3：术语“处理状态”没有说明文件尚不可用。</li><li>Q4：100% 与“上传完成”反馈可能错误地暗示最终成功。</li></ul><p>问题 ST-CW-03：阶段模型不清。应改为“文件已上传，正在处理”，保持任务 ID、进度阶段和可离开说明。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>处理失败时，页面显示错误码 <code>PARSER_42</code> 和“重试”。走查判断：首次用户无法把重试与“重新处理同一文件”关联，也不知道是否会重复上传。修复候选是“重新处理文件”，说明不重复创建版本，并给出可修正文件要求。</p><p>权限在登录期间撤销时，深链进入通用 404。为了防止资源泄露，系统可以不确认对象存在，但仍应说明“无法访问此项目或上传任务”及返回项目列表/申请权限路径。</p><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ID</th><th>问题</th><th>四问失败</th><th>证据</th><th>结论强度</th></tr></thead><tbody><tr><td>ST-CW-01</td><td>登录中断未说明保留任务</td><td>Q4</td><td>当前页面</td><td>自测潜在问题</td></tr><tr><td>ST-CW-02</td><td>续传范围不可预测</td><td>Q3</td><td>当前文案</td><td>自测潜在问题</td></tr><tr><td>ST-CW-03</td><td>上传与处理混合</td><td>Q1/Q4</td><td>状态与服务端数据</td><td>当前事实较强</td></tr><tr><td>ST-CW-04</td><td>错误码与重试含义不清</td><td>Q3</td><td>故障状态</td><td>自测潜在问题</td></tr></tbody></table><h3 id="外部补证" tabindex="-1">外部补证 <a class="header-anchor" href="#外部补证" aria-label="Permalink to &quot;外部补证&quot;">​</a></h3><ul><li>检查公开帮助是否区分上传与处理；</li><li>查支持问题中“100% 后找不到文件”；</li><li>用任务日志观察重复上传；</li><li>查看服务端重复版本数据；</li><li>找同伴按冻结任务执行，不提供路径。</li></ul><h2 id="自测后的修复规则" tabindex="-1">自测后的修复规则 <a class="header-anchor" href="#自测后的修复规则" aria-label="Permalink to &quot;自测后的修复规则&quot;">​</a></h2><p>每项修复必须对应失败问题：</p><ul><li>Q1 子目标失败：明确当前任务、阶段和下一步。</li><li>Q2 发现失败：调整入口位置、可见标签与状态，不只增大颜色。</li><li>Q3 关联失败：使用准确动作、对象和后果文案。</li><li>Q4 反馈失败：显示动作被接收、处理中、结果和恢复，并提供程序语义。</li></ul><p>修改后重复相同角色卡、任务和状态，避免换任务后宣称修复有效。</p><h2 id="与键盘和响应式结合" tabindex="-1">与键盘和响应式结合 <a class="header-anchor" href="#与键盘和响应式结合" aria-label="Permalink to &quot;与键盘和响应式结合&quot;">​</a></h2><p>认知走查关注理解，但正确动作若键盘不可达，也应记录实际失败并交给无障碍审计。窄屏可能隐藏入口、改变顺序或遮挡反馈，因此至少在支持的桌面/移动布局各走一遍。</p><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>设计者以“我能找到”回答 Q2：使用角色卡与界面线索。</li><li>为了模拟新用户故意装作看不见：依据可见证据与合理知识，不表演困惑。</li><li>四问回答没有反证和失败过程。</li><li>走查时打开标注或代码找正确路径。</li><li>只检查主路径，不检查等待、错误和恢复。</li><li>把自测预测写成真实用户结论。</li><li>修改后换输入和任务，无法比较。</li></ul><h2 id="可执行步骤" tabindex="-1">可执行步骤 <a class="header-anchor" href="#可执行步骤" aria-label="Permalink to &quot;可执行步骤&quot;">​</a></h2><ol><li>冻结产品版本、角色卡、任务、输入和完成标准。</li><li>折叠正确路径，准备主状态与失败条件。</li><li>延迟执行并隐藏设计/实现说明。</li><li>对每个动作回答四问、证据和反证。</li><li>记录熟悉度污染、错误动作和恢复。</li><li>按失败问题生成修复规则，不直接美化页面。</li><li>用相同任务、键盘和窄屏复测。</li><li>通过公开证据、日志、同伴任务或其他方法补证。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>自测“首次创建 API 密钥并安全保存”。</p><p>完成时应满足：</p><ul><li>角色卡明确知道与不知道什么；</li><li>任务不包含设置路径或按钮名；</li><li>每一步完整回答四问并记录熟悉度污染；</li><li>覆盖权限、一次性显示、复制失败、页面离开和密钥撤销；</li><li>说明密钥为何不能再次明文查看；</li><li>键盘与屏幕阅读器路径另行验证；</li><li>所有结论标为当前事实或自测假设，并有补证计划。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.ics.uci.edu/~redmiles/ics104-WQ06/Chapter_4/CognitiveWalkthroughRev2006.pdf" target="_blank" rel="noreferrer">Wharton、Rieman、Lewis、Polson：The Cognitive Walkthrough Method</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/predictable.html" target="_blank" rel="noreferrer">W3C WAI：Understanding Guideline 3.2 Predictable</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/focus-order.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 2.4.3 Focus Order</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/design/making-prototypes" target="_blank" rel="noreferrer">GOV.UK Service Manual：Making prototypes</a>（访问日期：2026-07-17）</li></ul>`,70)])])}const u=s(l,[["render",t]]);export{b as __pageData,u as default};
